dashboard.definition:
{
    "title": "Adoption and Engagement",
    "description": "Active users, seat utilization, and feature adoption.",
    "inputs": {
        "input_time": {
            "type": "input.timerange",
            "title": "Time Range",
            "options": { "token": "time", "defaultValue": "-30d@d,now" }
        }
    },
    "dataSources": {
        "ds_active_users": {
            "type": "ds.search",
            "name": "Active users",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:analytics:engagement 'ai.engagement.kind'=summaries | timechart span=1d max('ai.engagement.daily_active_users') as dau max('ai.engagement.weekly_active_users') as wau max('ai.engagement.monthly_active_users') as mau",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_seat_util": {
            "type": "ds.search",
            "name": "Seat utilization",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:analytics:engagement 'ai.engagement.kind'=summaries | stats latest('ai.engagement.monthly_active_users') as mau latest('ai.engagement.assigned_seats') as seats | eval seat_utilization_pct=round(mau/seats*100,1) | fields seat_utilization_pct",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_activity": {
            "type": "ds.search",
            "name": "Messages and conversations",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:analytics:engagement 'ai.engagement.kind'=summaries | timechart span=1d sum('ai.engagement.message.count') as messages sum('ai.engagement.conversation.count') as conversations",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_connectors": {
            "type": "ds.search",
            "name": "Connector usage",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:analytics:engagement 'ai.engagement.kind'=connectors | stats sum('ai.engagement.connector.distinct_users') as distinct_users by 'ai.engagement.connector.name' | sort -distinct_users | head 10 | rename ai.engagement.connector.name as connector",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_skills": {
            "type": "ds.search",
            "name": "Skill usage",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:analytics:engagement 'ai.engagement.kind'=skills | stats count by 'ai.governance.object_id' | sort -count | head 10 | rename ai.governance.object_id as skill",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        }
    },
    "visualizations": {
        "viz_active_users": {
            "type": "splunk.line",
            "title": "DAU / WAU / MAU",
            "dataSources": { "primary": "ds_active_users" },
            "options": { "xField": "_time" }
        },
        "viz_seat_util": {
            "type": "splunk.singlevalue",
            "title": "Seat Utilization (MAU / Seats)",
            "dataSources": { "primary": "ds_seat_util" },
            "options": { "majorField": "seat_utilization_pct", "unit": "%" }
        },
        "viz_activity": {
            "type": "splunk.column",
            "title": "Messages and Conversations",
            "dataSources": { "primary": "ds_activity" },
            "options": { "xField": "_time" }
        },
        "viz_connectors": {
            "type": "splunk.bar",
            "title": "Connector Usage by Distinct Users",
            "dataSources": { "primary": "ds_connectors" },
            "options": { "yField": "connector" }
        },
        "viz_skills": {
            "type": "splunk.bar",
            "title": "Top Skills",
            "dataSources": { "primary": "ds_skills" },
            "options": { "yField": "skill" }
        }
    },
    "layout": {
        "type": "grid",
        "globalInputs": [ "input_time" ],
        "structure": [
            { "item": "viz_active_users", "type": "block", "position": { "x": 0, "y": 0, "w": 800, "h": 300 } },
            { "item": "viz_seat_util", "type": "block", "position": { "x": 800, "y": 0, "w": 400, "h": 300 } },
            { "item": "viz_activity", "type": "block", "position": { "x": 0, "y": 300, "w": 1200, "h": 280 } },
            { "item": "viz_connectors", "type": "block", "position": { "x": 0, "y": 580, "w": 600, "h": 300 } },
            { "item": "viz_skills", "type": "block", "position": { "x": 600, "y": 580, "w": 600, "h": 300 } }
        ]
    }
}
